mapper.select:
SELECT
wr.*,
u.username as userName,
u.phone,
p.name as petName
FROM warning_record wr
LEFT JOIN user u ON wr.user_id = u.id
LEFT JOIN pet p ON wr.pet_id = p.id

    AND wr.user_id = #{userId}
    AND wr.pet_id = #{petId}
    AND wr.status = #{status}
    AND wr.warning_level = #{warningLevel}

ORDER BY wr.create_time DESC

    LIMIT #{offset}, #{size}

SELECT COUNT(*) FROM warning_record

    AND user_id = #{userId}
    AND pet_id = #{petId}
    AND status = #{status}
    AND warning_level = #{warningLevel}
